#pragma OPENCL EXTENSION cl_khr_int64_base_atomics : enable

#define BLOCKSIZE	256
#define ROW_LENGTH	BLOCKSIZE * 4
#define ROWS		4096

#define LOG_DIVISIONS	10
#define DIVISIONS		(1 << LOG_DIVISIONS)

__constant int constStartAddr[DIVISIONS + 1]; 
__constant int finalStartAddr[DIVISIONS + 1]; 
__constant int nullElems[DIVISIONS]; 

__device__ float4 sortElem(float4 r) {
	float4 nr;

	nr.x = (r.x > r.y) ? r.y : r.x; 
	nr.y = (r.y > r.x) ? r.y : r.x; 
	nr.z = (r.z > r.w) ? r.w : r.z; 
	nr.w = (r.w > r.z) ? r.w : r.z; 

	r.x = (nr.x > nr.z) ? nr.z : nr.x; 
	r.y = (nr.y > nr.w) ? nr.w : nr.y; 
	r.z = (nr.z > nr.x) ? nr.z : nr.x; 
	r.w = (nr.w > nr.y) ? nr.w : nr.y; 

	nr.x = r.x; 
	nr.y = (r.y > r.z) ? r.z : r.y; 
	nr.z = (r.z > r.y) ? r.z : r.y; 
	nr.w = r.w; 
	return nr; 
}

__device__ float4 getLowest(float4 a, float4 b)
{

	a.x = (a.x < b.w) ? a.x : b.w; 
	a.y = (a.y < b.z) ? a.y : b.z; 
	a.z = (a.z < b.y) ? a.z : b.y; 
	a.w = (a.w < b.x) ? a.w : b.x; 
	return a; 
}

__device__ float4 getHighest(float4 a, float4 b)
{
	b.x = (a.w >= b.x) ? a.w : b.x; 
	b.y = (a.z >= b.y) ? a.z : b.y; 
	b.z = (a.y >= b.z) ? a.y : b.z; 
	b.w = (a.x >= b.w) ? a.x : b.w; 
	return b; 
}

__global__ void
mergeSortFirst(float4 *result, int listsize, const float4 *texData) 
{
    int bx = blockIdx.x;

    int idx = bx*blockDim.x + threadIdx.x;

	if(idx < listsize/4){
		float4 r = texData[idx];
		result[idx] = sortElem(r); 
	}
}

__global__ void
mergeSortPass(float4 *result, int nrElems, int threadsPerDiv, const float4 *texData) 
{
	int tid = (blockIdx.x * blockDim.x) + threadIdx.x; 

	int division = tid / threadsPerDiv; 
	if(division >= DIVISIONS) return; 

	int int_tid = tid - division * threadsPerDiv; 
	int Astart = constStartAddr[division] + int_tid * nrElems; 

	int Bstart = Astart + nrElems/2;
	float4 *resStart = &(result[Astart]); 

	if(Astart >= constStartAddr[division + 1]) 
		return; 
	if(Bstart >= constStartAddr[division + 1]){
		for(int i=0; i<(constStartAddr[division + 1] - Astart); i++)
		{
			resStart[i] = texData[Astart + i]; 
		}
		return; 
	}

	int aidx = 0; 
	int bidx = 0; 
	int outidx = 0; 
	float4 a, b;
	a = texData[Astart + aidx];  
	b = texData[Bstart + bidx]; 

	while(true)
	{
		float4 nextA = texData[Astart + aidx + 1]; 
		float4 nextB = texData[Bstart + bidx + 1]; 

		float4 na = getLowest(a,b); 
		float4 nb = getHighest(a,b); 
		a = sortElem(na); 
		b = sortElem(nb); 

		resStart[outidx++] = a; 

		bool elemsLeftInA; 
		bool elemsLeftInB;

		elemsLeftInA = (aidx + 1 < nrElems/2); 
		elemsLeftInB = (bidx + 1 < nrElems/2) && (Bstart + bidx + 1 < constStartAddr[division + 1]); 

		if(elemsLeftInA){
			if(elemsLeftInB){
				if(nextA.x < nextB.x) { aidx += 1; a = nextA; }  
				else { bidx += 1;  a = nextB; }
			}
			else {
				aidx += 1; a = nextA;
			}
		}
		else {
			if(elemsLeftInB){
				bidx += 1;  a = nextB;
			}
			else {
				break; 
			}
		}

	}
	resStart[outidx++] = b;
}

__global__ void
mergepack(float *orig, float *result) 
{
	int idx = (blockIdx.x * blockDim.x) + threadIdx.x; 
	int division = blockIdx.y; 

	if((finalStartAddr[division] + idx) >= finalStartAddr[division + 1]) return; 
	result[finalStartAddr[division] + idx] = orig[constStartAddr[division]*4 + nullElems[division] + idx]; 
}
